import os; p="src/lib/game/nodes.ts"; c=open(p,encoding="utf-8").read(); N=chr(10); old=N.join(["  try {","    const { Pool } = require(\"pg\");","    const pool = new Pool({ connectionString: process.env.DATABASE_URL || \"postgresql://postgres:password@localhost:5432/xiuxian\" });","    const res = await pool.query(\"SELECT content, metadata FROM world_vectors LIMIT 5\");","    ragContext = res.rows.map((r: any) => r.content).join(String.fromCharCode(10));","    await pool.end();","    console.log(\"[RAG] Found \" + res.rows.length + \" context chunks\");","  } catch (err) {","    console.log(\"[RAG] pgvector query failed, using fallback\");","    ragContext = \"修仙界常言：练气期修士寿元百年。当前地点：青云山脉外围。\";","  }"]); new=N.join(["  try {","    const { searchVectors } = require(\"@/lib/vector-store\");","    const results = await searchVectors(playerId, query, 5);","    ragContext = results.map((r: any) => r.content).join(String.fromCharCode(10));","    console.log(\"[RAG] Found \" + results.length + \" context chunks for conversation \" + playerId);","  } catch (err) {","    console.log(\"[RAG] Search failed, using fallback\");","    ragContext = \"修仙界常言：练气期修士寿元百年。当前地点：青云山脉外围。\";","  }"]); c=c.replace(old,new); open(p,"w",encoding="utf-8").write(c); print("rag replaced:","searchVectors" in c)